	cfg := "version: \"1.0\"\nbead:\n  id_prefix: \"pt\"\n"
	if err := os.WriteFile(filepath.Join(ddxDir, "config.yaml"), []byte(cfg), 0o644); err != nil {
		t.Fatal(err)
	}
}

func writeEndpointConfig(t *testing.T, workDir string) string {
